func newOrdersPlaceCmd(flags *rootFlags) *cobra.Command {
	var reuseLast bool
	var confirm bool
	var maxBudget float64
	var confirmOverBudget bool
	var tipSpec string
	var showBrowser bool
	var timeout time.Duration
	var chromeProfile string
	var userDataDir string

	cmd := &cobra.Command{
		Use:   "place",
		Short: "Place the active planned order through a Chrome checkout session",
		Example: `  ordertogo-pp-cli orders place --confirm --max 30 --json
  ordertogo-pp-cli orders place --confirm --max 30 --show-browser`,
		Annotations: map[string]string{"pp:typed-exit-codes": "0,4,5"},
		RunE: func(cmd *cobra.Command, args []string) error {
			if !confirm {
				return usageErr(fmt.Errorf("--confirm is required"))
			}
			if maxBudget <= 0 {
				return usageErr(fmt.Errorf("--max is required"))
			}
			if verifyMode() {
				return printJSONFiltered(cmd.OutOrStdout(), map[string]any{
					"status": "would_place",
					"plan":   "active-cart",
					"max":    maxBudget,
				}, flags)
			}
			cart, err := loadActiveCart()
			if err != nil {
				return notFoundErr(fmt.Errorf("reading active cart: %w", err))
			}
			if cart.Totals.Total > maxBudget && !confirmOverBudget {
				return budgetError(flags, "active cart total exceeds --max", maxBudget, cart.Totals.Total)
			}
			if tipSpec != "" && tipSpec != "auto" {
				// PATCH: Allow final tip override before opening the browser while
				// keeping the budget guard ahead of any Chrome side effects.
				tip, err := parseTip(tipSpec, cart.Totals.Subtotal, nil)
				if err != nil {
					return usageErr(err)
				}
				cart.Totals.Tip = tip
				cart.Totals.Total = roundMoney(cart.Totals.Subtotal + cart.Totals.Tax + cart.Totals.Tip)
				if cart.Totals.Total > maxBudget && !confirmOverBudget {
					return budgetError(flags, "active cart total exceeds --max after tip override", maxBudget, cart.Totals.Total)
				}
			}
			out, screenshotPath, err := placeWithChrome(cmd.Context(), cart, showBrowser, timeout, chromeProfile, userDataDir)
			if err != nil {
				return orderPlaceFailure(flags, err, screenshotPath)
			}
			return printJSONFiltered(cmd.OutOrStdout(), out, flags)
		},
	}
	cmd.Flags().BoolVar(&reuseLast, "reuse-last", false, "Reuse the last active-cart plan")
	cmd.Flags().BoolVar(&confirm, "confirm", false, "Confirm that the order should be placed")
	cmd.Flags().Float64Var(&maxBudget, "max", 0, "Maximum allowed total in dollars (required)")
	cmd.Flags().BoolVar(&confirmOverBudget, "confirm-over-budget", false, "Allow totals over --max")
	cmd.Flags().StringVar(&tipSpec, "tip", "auto", "Tip as auto, pct%, or dollars")
	cmd.Flags().BoolVar(&showBrowser, "show-browser", false, "Show the Chrome browser window")
	cmd.Flags().DurationVar(&timeout, "timeout", 5*time.Minute, "Chrome checkout timeout")
	cmd.Flags().StringVar(&chromeProfile, "chrome-profile", "Default", "Chrome profile directory name")
	cmd.Flags().StringVar(&userDataDir, "user-data-dir", "", "Chrome user data directory")
	_ = reuseLast
	return cmd
}

// pp:client-call
// placeWithChrome drives a real chromedp.Run session against
// https://www.ordertogo.com to complete the Braintree DropIn checkout
